-- =================================================================
-- VitalTrack — seed data
-- Prerequisite: run  npm run db:push  first (creates tables)
-- Run with:   psql "$DATABASE_URL" < seed.sql
-- Default login: gowthamd / Digi@8631
-- =================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;

BEGIN;

-- ─── 1. Seed user ─────────────────────────────────────────────────
  'a0000000-0000-4000-8000-000000000001',
  'gowthamd',
  crypt('Digi@8631', gen_salt('bf', 12)),
  'Gowtham',
  175.0
) ON CONFLICT (email) DO NOTHING;

-- ─── 2. Weight entries ────────────────────────────────────────────
ON CONFLICT DO NOTHING;

-- ─── 3. Habits ────────────────────────────────────────────────────
-- CSV colour mapping: Cyan → #06b6d4, Blue → #3b82f6, Red → #ef4444
ON CONFLICT DO NOTHING;

-- ─── 4. Habit completions (from epoch-ms timestamps) ──────────────
-- Temp table holds raw CSV data; a CASE maps csv habit_id → uuid.
CREATE TEMP TABLE _actions (h int, t bigint);

SELECT
  CASE a.h
    WHEN 1 THEN 'b0000000-0000-4000-8000-000000000001'::uuid
    WHEN 2 THEN 'b0000000-0000-4000-8000-000000000002'::uuid
    WHEN 3 THEN 'b0000000-0000-4000-8000-000000000003'::uuid
    WHEN 4 THEN 'b0000000-0000-4000-8000-000000000004'::uuid
    WHEN 5 THEN 'b0000000-0000-4000-8000-000000000005'::uuid
    WHEN 6 THEN 'b0000000-0000-4000-8000-000000000006'::uuid
    WHEN 7 THEN 'b0000000-0000-4000-8000-000000000007'::uuid
    WHEN 9 THEN 'b0000000-0000-4000-8000-000000000009'::uuid
  END,
  'a0000000-0000-4000-8000-000000000001'::uuid,
  (to_timestamp(a.t::double precision / 1000))::date
FROM _actions a
ON CONFLICT DO NOTHING;

DROP TABLE _actions;

COMMIT;
